import Foundation

enum LogLevel {
    case debug, info, warning, error
}

class AnalyticsDebugger {
    static let shared = AnalyticsDebugger()
    private var environment: String = "production" // Change as needed

    private init() {}

    func log(_ message: String, level: LogLevel = .info) {
        #if DEBUG
        if environment == "development" || level != .debug {
            NSLog("[\(level)] \(message)")
        }
        #else
        if level != .debug {
            NSLog("[\(level)] \(message)")
        }
        #endif
    }

    func trackAuthenticationFlow(userId: String, email: String) {
        log("Authentication flow started for user: \(userId), email: \(email)", level: .info)
    }

    func trackAPICall(endpoint: String, requestPayload: [String: Any], responsePayload: [String: Any]) {
        let redactedRequest = redactSensitiveData(from: requestPayload)
        let redactedResponse = redactSensitiveData(from: responsePayload)
        log("API call to \(endpoint) with request: \(redactedRequest) and response: \(redactedResponse)", level: .debug)
    }

    func trackUserDataChange(userId: String, changes: [String: Any]) {
        let redactedChanges = redactSensitiveData(from: changes)
        log("User data changed for user: \(userId) with changes: \(redactedChanges)", level: .info)
    }

    func trackErrorCondition(error: Error, userId: String?) {
        log("Error occurred: \(error.localizedDescription) for user: \(userId ?? "unknown")", level: .error)
