    private func redactSensitiveData(from data: [String: Any]) -> [String: Any] {
        var redactedData = data
        let sensitiveKeys = ["password", "token", "secret", "ssn"]
        for key in sensitiveKeys {
            if redactedData.keys.contains(key) {
                redactedData[key] = "REDACTED"
